import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/ravel_todo.BYbdUFoq.js";const s=JSON.parse(`{"title":"Міграція мапінгів за допомогою Ravel","description":"Дізнайтеся, як мігрувати обфусковані мапінги вашого мода за допомогою Ravel.","frontmatter":{"title":"Міграція мапінгів за допомогою Ravel","description":"Дізнайтеся, як мігрувати обфусковані мапінги вашого мода за допомогою Ravel.","authors":["cassiancc","deirn"],"files":[]},"headers":[],"relativePath":"uk_ua/develop/migrating-mappings/ravel.md","filePath":"translated/uk_ua/develop/migrating-mappings/ravel.md","lastUpdated":1770561656000}`);var c={name:`uk_ua/develop/migrating-mappings/ravel.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Міграція мапінгів за допомогою Ravel <a class="header-anchor" href="#h1" aria-label="Permalink to “Міграція мапінгів за допомогою Ravel”">​</a></h1><p><a href="https://github.com/badasintended/ravel" target="_blank" rel="noreferrer">Ravel</a> — це плаґін для IntelliJ IDEA для переналаштування вихідних файлів на основі <a href="https://plugins.jetbrains.com/docs/intellij/psi.html" target="_blank" rel="noreferrer">PSI IntelliJ</a> і <a href="https://github.com/FabricMC/mapping-io" target="_blank" rel="noreferrer">Mapping-IO</a>. Він підтримує переналаштування Java, Kotlin, міксинів (написані на Java), Class Tweaker і розширювачі доступу.</p><p>Установіть його з <a href="https://plugins.jetbrains.com/plugin/28938-ravel-remapper" target="_blank" rel="noreferrer">JetBrains Marketplace</a> або завантажте ZIP-файл з <a href="https://github.com/badasintended/ravel/releases" target="_blank" rel="noreferrer">випусків GitHub</a> і встановіть його, натиснувши значок шестірні в налаштуваннях плаґіна та натиснувши <strong>встановити плаґін з носія</strong>.</p><p>![Установлення плаґіна IDEA з носія(/assets/develop/misc/migrating-mappings/idea_local_plugin.png)</p><h2 id="migrating-mappings" tabindex="-1">Міграція мапінгів <a class="header-anchor" href="#migrating-mappings" aria-label="Permalink to “Міграція мапінгів”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Унесіть будь-які зміни, перш ніж намагатися переналаштувати свої джерела! <strong>Поки що не змінюйте свій <code>gradle.properties</code> або <code>build.gradle</code>!</strong></p></div><p>Далі натисніть ПКМ по файлу, відкритий у редакторі, і виберіть <strong>Refactor</strong> &gt; <strong>Remap Using Ravel</strong>*</p><p><img src="/assets/develop/misc/migrating-mappings/ravel_right_click.png" alt="ПКМ у меню" loading="lazy"></p><p>Відкриється таке діалогове вікно. Ви також можете відкрити діалогове вікно, натиснувши <strong>Refactor</strong> у верхньому меню.</p><p><img src="/assets/develop/misc/migrating-mappings/ravel_dialog.png" alt="Діалог Ravel" loading="lazy"></p><p>Далі додайте мапінги, натиснувши значок +. Натисніть опцію завантаження, якщо у вас їх ще немає.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Якщо ви не бачите кнопку завантаження, оновіть Ravel до 0.3 або вище.</p></div><ul><li>Для переходу від мапінги Yarn до Mojang спочатку додайте файл Yarn <code>mappings.tiny</code>, виберіть <code>named</code> як <strong>source</strong> простір імен і <code>official</code> як <strong>destination</strong> простір імен. Потім додайте файл Mojang <code>client.txt</code> і виберіть <code>target</code> як <strong>source</strong> простір імен і <code>source</code> як <strong>destination</strong> простір імен.</li><li>Для переходу від мапінгів Mojang до Yarn спочатку додайте <code>client.txt</code> Mojang, цього разу вибравши <code>source</code> як <strong>source</strong> і <code>target</code> як <strong>destination</strong>. Потім додайте Yarn <code>mappings.tiny</code> і виберіть <code>official</code> як <strong>source</strong> і <code>named</code> як <strong>destination</strong>.</li></ul><p>Потім виберіть модулі, які потрібно змінити, натиснувши значок + або значок ліворуч, щоб додати всі модулі.</p><p>Потім натисніть <strong>OK</strong> і дочекайтеся завершення ремапінгу.</p><h3 id="updating-gradle" tabindex="-1">Оновлення Gradle <a class="header-anchor" href="#updating-gradle" aria-label="Permalink to “Оновлення Gradle”">​</a></h3><p>Після завершення ремапування замініть свої мапінги в <code>build.gradle</code> вашого мода.</p><div class="language-groovy line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">groovy</span><pre class="shiki shiki-themes github-light github-dark has-diff" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dependencies {</span></span>
<span class="line diff remove"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mappings </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;net.fabricmc:yarn:\${project.yarn_mappings}:v2&quot;</span></span>
<span class="line diff add"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mappings loom</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">officialMojangMappings() </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // Or the reverse if you&#39;re migrating from Mojang Mappings to Yarn</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Також оновіть свій <code>gradle.properties</code>, видаліть параметр <code>yarn_mappings</code> або оновіть його до того, який ви використовуєте.</p><div class="language-properties line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark has-diff" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line diff remove"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">yarn_mappings</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=1.21.11+build.3 </span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="final-changes" tabindex="-1">Кінцеві зміни <a class="header-anchor" href="#final-changes" aria-label="Permalink to “Кінцеві зміни”">​</a></h3><p>Ось і основна частина роботи виконана! Тепер ви захочете переглянути вихідний код, щоб перевірити потенційно застарілі цілі міксина або код, який не було переназначено.</p><p>Для проблем, які виявляє Ravel, ви можете виконати пошук (<kbd>Ctrl</kbd>+<kbd>Shift</kbd>+<kbd>F</kbd>) за запитом <code>TODO(Ravel)</code>.</p><p><img src="/assets/develop/misc/migrating-mappings/ravel_todo.png" alt="Пошук завдань Ravel" loading="lazy"></p><p>Такі інструменти, як <a href="https://mappings.dev/" target="_blank" rel="noreferrer">mappings.dev</a> або <a href="https://linkie.shedaniel.dev/mappings?namespace=yarn&amp;translateMode=ns&amp;translateAs=mojang_raw&amp;search=&amp;version=1.21.11" target="_blank" rel="noreferrer">Linkie</a>, допоможуть ознайомитись із вашими новими мапінгами.</p>`,25)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};